use rand::prelude::*;
use std::sync::{Mutex, Arc};
use std::thread;

struct ThreadSafeRng {
    inner: Mutex<ThreadRng>,
}

impl ThreadSafeRng {
    fn new() -> Self {
        Self { 
            inner: Mutex::new(ThreadRng::new()) 
        }
    }

    fn generate_u64(&self) -> u64 {
        let mut guard = self.inner.lock().unwrap();
        guard.next_u64()
    }
}

struct ThreadRng { _rng: StdRng }

impl ThreadRng {
    fn new() -> Self {
        Self { _rng: StdRng::from_entropy() }
    }

    fn next_u64(&mut self) -> u64 {
        self._rng.gen()
    }
}

fn main() {
    let shared_rng = Arc::new(ThreadSafeRng::new());
    let num_threads = 10;
    let mut handles = vec![];

    for i in 0..num_threads {
        let rng_clone = Arc::clone(&shared_rng);
        let handle = thread::spawn(move || {
            let random_val = rng_clone.generate_u64();
            println!("Thread {} got: {}", i, random_val);
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }
}

use rand::prelude::*;
use std::time::{SystemTime, UNIX_EPOCH};

#[derive(Debug)]
struct TelemetryData {
    device_id: String,
    timestamp: u64,
    reading: f32,
}

fn generate_secure_random_string(length: usize) -> String {
    let mut chars = Vec::with_capacity(length);
    const CHARSET: &[u8] = b"ABCDEFGHIJKLMNOPDISPLAYZ09";
    let mut rng = thread_rng();

    for _ in 0..length {
        let idx = rand::distributions::Uniform::new(0, CHARSET.len() as u32)
            .sample(&mut rng) as usize;
        chars.push(CHARSET[idx]);
    }
    String::from_utf8(chars).unwrap()
}

fn main() {
    let device_id = generate_secure_random_string(12);
    println!("Generated Device ID: {}", device_id);

    let now = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs();

