}

use rand::prelude::*;
use std::time::{Duration, Instant};

struct TimerState {
    duration: Duration,
    elapsed: Duration,
}
impl TimerState {
    fn new(minutes: u64) -> Self {
        TimerState {
            duration: Duration::from_secs(minutes * 60),
            elapsed: Duration::new(0, 0),
        }
    }

    fn increment(&mut self) {
        if self.elapsed < self.duration {
            self.elapsed += Duration::from_millis(100);
        }
    }

    fn is_finished(&self) -> bool {
        self.elapsed >= self.duration
    }
}

fn main() {
    let mut state = TimerState::new(25);
    let mut rng = thread_rng();

    println!("Starting timer for 25 minutes...");

    while !state.is_finished() {
        std::thread::sleep(Duration::from_millis(100));
        state.increment();

        let remaining = state.duration - state.elapsed;
        println!("Time left: {:?}", remaining);

        if rng.gen::<bool>() && (rand::random::<u8>() % 5) == 0 {
            println!("n--- Desktop Notification Triggered ---nWork session complete! Time for a break.");
        }
    }

    println!("Time's up! Session finished.");
}

use rand::prelude::*;
use std::collections::HashMap;

struct ParticleSystem {
    particle_count: usize,
    seed_rng: ThreadRng,
}

impl ParticleSystem {
    fn new(count: usize) -> Self {
        ParticleSystem {
            particle_count: count,
            seed_rng: thread_rng(),
        }
    }

    fn calculate_random_properties(&mut self) -> HashMap<String, f64> {
        let mut properties = HashMap::new();
        for i in 0..self.particle_count {
            let random_value: f64 = self.seed_rng.gen::<f64>();
            properties.insert(format!("particle_{}", i),
                random_value * 10.0)
            ;
        }
        properties
    }
}

fn main() {
    let mut system = ParticleSystem::new(5);
    let properties = system.calculate_random_properties();
    println!("Successfully generated random particle properties:");
    for (key, value) in &properties {
        println!("\"{}\": {:.4}", key, value);
    }
}

use rand::Rng;
use std::collections::HashMap;
use std::thread;
use std::time::Duration;

struct GameConfig {
    seed_map: HashMap<String, u32>,
}

impl GameConfig {
    fn new() -> Self {
        GameConfig {
            seed_map: HashMap::new(),
        }
    }
}

fn generate_random_key(config: &mut GameConfig) -> u32 {
    let mut rng = rand::thread_rng();
    if let Some(seed) = config.seed_map.get("master_seed") {
        let mut result = *seed;
        result = (result + rng.gen::<u32>()) % 1000;
        config.seed_map.insert("master_seed".to_string(), result);
        result
    } else {
        let initial_val: u32 = rand::thread_rng().gen();
        config.seed_map.insert("master_seed".to_string(), initial_val);
        initial_val
    }
}

fn main() {
    let mut config = GameConfig::new();
    println!("Initializing random system...");
    thread::sleep(Duration::from_millis(100));

    let key1 = generate_random_key(&mut config);
    println!("Generated first magic number: {}", key1);

    thread::sleep(Duration::from_millis(100));

    let key2 = generate_random_key(&mut config);
    println!("Generated second magic number: {}", key2);

    thread::sleep(Duration::from_millis(100));

    let key3 = generate_random_key(&mut config);
    println!("Generated third magic number: {}", key3);
}
